  "text": "func (b *backend) handleRoleTagLogin(ctx context.Context, s logical.Storage, roleName string, roleEntry *awsRoleEntry, instance *ec2.Instance) (*roleTagLoginResponse, error) {
n1: 	if roleEntry == nil {
n2: 		return nil, fmt.Errorf("nil role entry")
