n3: 	if instance == nil {
n4: 		return nil, fmt.Errorf("nil instance")
	}

	// Input validation on instance is not performed here considering
	// that it would have been done in validateInstance method.
n5: 	tags := instance.Tags
n6: 	if tags == nil || len(tags) == 0 {
n7: 		return nil, fmt.Errorf("missing tag with key %q on the instance", roleEntry.RoleTag)
	}

	// Iterate through the tags attached on the instance and look for
	// a tag with its 'key' matching the expected role tag value.
n8: 	rTagValue := ""
n9: 	for _, tagItem := range tags {
n10: 		if tagItem.Key != nil && *tagItem.Key == roleEntry.RoleTag {
n11: 			rTagValue = *tagItem.Value
n12: 			break
		}
	}

	// If 'role_tag' is enabled on the role, and if a corresponding tag is not found
	// to be attached to the instance, fail.
n13: 	if rTagValue == "" {
n14: 		return nil, fmt.Errorf("missing tag with key %q on the instance", roleEntry.RoleTag)
	}

	// Parse the role tag into a struct, extract the plaintext part of it and verify its HMAC
n15: 	rTag, err := b.parseAndVerifyRoleTagValue(ctx, s, rTagValue)
n16: 	if err != nil {
n17: 		return nil, err
	}

	// Check if the role name with which this login is being made is same
	// as the role name embedded in the tag.
n18: 	if rTag.Role != roleName {
n19: 		return nil, fmt.Errorf("role on the tag is not matching the role supplied")
	}

	// If instance_id was set on the role tag, check if the same instance is attempting to login
n20: 	if rTag.InstanceID != "" && rTag.InstanceID != *instance.InstanceId {
n21: 		return nil, fmt.Errorf("role tag is being used by an unauthorized instance")
	}

	// Check if the role tag is deny listed
n22: 	denyListEntry, err := b.lockedDenyLististRoleTagEntry(ctx, s, rTagValue)
n23: 	if err != nil {
n24: 		return nil, err
	}
n25: 	if denyListEntry != nil {
n26: 		return nil, fmt.Errorf("role tag is deny listed")
	}

